UPDATE content_post
SET status = #{status}
WHERE post_id = #{postId}
  AND status = #{expectedStatus}

UPDATE content_post
SET status = #{status}
WHERE post_id = #{postId}
  AND user_id = #{userId}

UPDATE content_post
SET content_text = #{contentText},
    media_info = #{mediaInfo},
    location_info = #{locationInfo},
    version_num = #{versionNum},
    is_edited = #{isEdited},
    status = #{status},
    visibility = #{visibility}
WHERE post_id = #{postId}
  AND version_num = #{expectedVersion}

mapper.select:
SELECT post_id, user_id, content_text, media_type, media_info, location_info, status, visibility, version_num, is_edited, create_time
FROM content_post
WHERE user_id = #{userId}
  AND status IN (1, 2)

    AND (create_time < #{cursorTime}
         OR (create_time = #{cursorTime} AND post_id < #{cursorPostId}))

ORDER BY create_time DESC, post_id DESC
LIMIT #{limit}

SELECT post_id, user_id, content_text, media_type, media_info, location_info, status, visibility, version_num, is_edited, create_time FROM content_post WHERE status = 2
AND (create_time < #{cursorTime} OR (create_time = #{cursorTime} AND post_id < #{cursorPostId}))
ORDER BY create_time DESC, post_id DESC LIMIT #{limit}
